code = """import json
import pandas as pd

# Access previous tool results
reviews = var_call_wt36KiikhqPYkJqQBftXyzaS
books_file = var_call_7LoAnscXfBmJww5Si2YXcq2N

# Load books JSON from file
with open(books_file, 'r', encoding='utf-8') as f:
    books = json.load(f)

# Normalize reviews into DataFrame
rev_df = pd.DataFrame(reviews)
# Convert numeric types
rev_df['avg_rating'] = rev_df['avg_rating'].astype(float)
rev_df['review_count'] = rev_df['review_count'].astype(int)

# Map purchase_id like 'purchaseid_83' -> 'bookid_83'
rev_df['book_id'] = rev_df['purchase_id'].str.replace('purchaseid_', 'bookid_')

# Books DataFrame
books_df = pd.DataFrame(books)

# Ensure categories field present and filter to those containing "Children's Books" (case-insensitive)
books_df['categories_str'] = books_df['categories'].astype(str)
books_children = books_df[books_df['categories_str'].str.lower().str.contains("children")] 

# Merge on book_id
merged = pd.merge(rev_df, books_children, left_on='book_id', right_on='book_id', how='inner')

# Select and sort
merged['avg_rating'] = merged['avg_rating'].astype(float)
merged['review_count'] = merged['review_count'].astype(int)
merged = merged.sort_values(by=['avg_rating', 'review_count'], ascending=[False, False])

result = []
for _, row in merged.iterrows():
    result.append({
        'title': row.get('title'),
        'book_id': row.get('book_id'),
        'purchase_id': row.get('purchase_id'),
        'avg_rating': row.get('avg_rating'),
        'review_count': row.get('review_count'),
        'categories': row.get('categories')
    })

# Print result in required format as JSON string
print("__RESULT__:")
print(json.dumps(result))"""

